#!/usr/bin/env bun
// Generated by minsky compile. Do not edit directly.
// Source: .minsky/hooks/ask-permission-bridge.ts

// Approved-Ask ↔ harness-permission bridge (mt#2823).
//
// PreToolUse hook on `Bash` + `mcp__minsky__session_exec`: when the pending
// command matches a live, unconsumed, TTL-bound ask-grant
// (`.minsky/hooks/ask-grant-store.ts`) AND the referenced
// `authorization.approve` Ask verifies server-side as operator-approved,
// emit the harness `permissionDecision: "allow"` — so an approval routed
// through the Ask substrate authorizes the action without a SECOND manual
// approval at the harness classifier (the c01f89af double-approval
// round-trip this task exists to close).
//
// ## Decision ladder (fail-safe by construction)
//
//   1. subagent invocation (agent_id present)      → silent defer (exit 0)
//   2. tool not Bash/session_exec, or no command   → silent defer
//   3. store unreadable                            → defer + stderr warning
//   4. no matching grant                           → silent defer (the
//      overwhelmingly common path — normal permission flow applies; per the
//      vendor hook contract, exit 0 with no output is "no decision")
//   5. grant matched, ask verification UNAVAILABLE → defer + warning (never
//      allow on unverifiable state)
//   6. grant matched, ask verification NEGATIVE    → DENY + loud warning
//      (fabrication signal — a grant whose ask is absent/unapproved/non-
//      operator-attributed; the grant is left unconsumed for inspection)
//   7. grant matched + ask verified               → consume the grant
//      (one-shot, BEFORE emitting the decision; losing the consume race
//      defers), emit best-effort `hook.fired {decision:"overridden"}`
//      audit event, then `permissionDecision: "allow"` with an audit reason
//      naming the askId.
//
// Deny-precedence: the harness combines PreToolUse decisions with deny
// outranking allow, so this bridge structurally cannot bypass other guards
// (git/gh CLI ban, bypass-merge guard) — it only preempts the permission
// classifier when no other hook denies.
//
// Authoritative source (recorded in the mt#2823 spec's Plan decision):
// https://code.claude.com/docs/en/hooks — PreToolUse `hookSpecificOutput`
// `permissionDecision: "allow" | "deny" | "ask"`; exit 0 with no output
// defers to the normal permission flow.
//
// @see .minsky/hooks/ask-grant-store.ts — grant store (one-shot, TTL)
// @see .minsky/hooks/ask-verification.ts — server-side ask verification
// @see scripts/grant-ask-action.ts — issuance surface
// @see docs/architecture/hooks/ask-permission-bridge.md

import { readInput, writeOutput, execWithPath } from "./types";
import type { ToolHookInput } from "./types";
import {
  getAskGrantStorePath,
  readAskGrantStore,
  findValidAskGrant,
  consumeAskGrant,
  type AskGrant,
} from "./ask-grant-store";
import { verifyApprovedAsk, type AskVerificationResult } from "./ask-verification";

const BRIDGE_TOOLS = new Set(["Bash", "mcp__minsky__session_exec"]);

/** Extract the command string the grant pattern is matched against. */
export function extractCommand(
  toolName: string,
  toolInput: Record<string, unknown>
): string | null {
  if (!BRIDGE_TOOLS.has(toolName)) return null;
  const command = toolInput?.command;
  return typeof command === "string" && command.length > 0 ? command : null;
}

/** Build the allow-decision audit reason. Exported for tests. */
export function buildAllowReason(grant: AskGrant): string {
  return (
    `[ask-permission-bridge] allowed by operator-approved ask ${grant.askId} ` +
    `(one-shot grant issued ${grant.issuedAt} consumed; reason: ${grant.reason})`
  );
}

/** Build the deny-decision reason for a verification-failed grant. Exported for tests. */
export function buildDenyReason(grant: AskGrant, verification: AskVerificationResult): string {
  return (
    `[ask-permission-bridge] grant referencing ask ${grant.askId} FAILED server-side ` +
    `verification: ${verification.detail}. This looks like a fabricated or stale grant — ` +
    `denying. The grant is left unconsumed for inspection at the ask-grant store.`
  );
}

function emitAuditEvent(grant: AskGrant, command: string): void {
  // Best-effort: the allow decision must not depend on audit-event delivery,
  // but a failure is logged loudly to stderr (visible in hook debug output).
  const payload = JSON.stringify({
    hook: "ask-permission-bridge",
    decision: "overridden",
    subject: `${grant.askId} → ${grant.tool}: ${command.slice(0, 200)}`,
  });
  const result = execWithPath(["minsky", "events", "emit", "hook.fired", "--payload", payload], {
    timeout: 5000,
  });
  if (result.exitCode !== 0) {
    process.stderr.write(
      `[ask-permission-bridge] WARNING: audit event emission failed (exit ${result.exitCode}); ` +
        `the allow itself is recorded in the permission-decision reason.\n`
    );
  }
}

async function main(): Promise<void> {
  const input = await readInput<ToolHookInput>();

  // (1) Main-agent mechanism only — subagent calls keep the normal flow.
  if (input.agent_id) return;

  // (2) Tool / command extraction.
  const command = extractCommand(input.tool_name, input.tool_input ?? {});
  if (!command) return;

  // (3) Store read — conservative: unreadable store means no allow.
  const storePath = getAskGrantStorePath();
  const read = readAskGrantStore(storePath);
  if (read.status === "error") {
    process.stderr.write(
      `[ask-permission-bridge] WARNING: grant store unreadable (${read.message}); ` +
        `deferring to normal permission flow.\n`
    );
    return;
  }

  // (4) Grant match.
  const grant = findValidAskGrant(read.grants, { tool: input.tool_name, command }, Date.now());
  if (!grant) return;

  // (5)/(6) Server-side re-verification of the referenced Ask.
  const verification = verifyApprovedAsk(grant.askId);
  if (verification.verdict === "unavailable") {
    process.stderr.write(
      `[ask-permission-bridge] WARNING: could not verify ask ${grant.askId} server-side ` +
        `(${verification.detail}); deferring to normal permission flow — never allowing on ` +
        `unverifiable state.\n`
    );
    return;
  }
  if (verification.verdict === "not-approved") {
    writeOutput({
      hookSpecificOutput: {
        hookEventName: "PreToolUse",
        permissionDecision: "deny",
        permissionDecisionReason: buildDenyReason(grant, verification),
      },
    });
    return;
  }

  // (7) One-shot consumption BEFORE emitting the allow.
  const consumed = consumeAskGrant(storePath, grant);
  if (!consumed) {
    process.stderr.write(
      `[ask-permission-bridge] grant for ask ${grant.askId} was already consumed; ` +
        `deferring to normal permission flow.\n`
    );
    return;
  }

  emitAuditEvent(grant, command);

  writeOutput({
    hookSpecificOutput: {
      hookEventName: "PreToolUse",
      permissionDecision: "allow",
      permissionDecisionReason: buildAllowReason(grant),
    },
  });
}

if (import.meta.main) {
  main().catch((err) => {
    // A crashed bridge must never block or allow anything — swallow to
    // exit 0 (defer) with a loud stderr trace.
    process.stderr.write(
      `[ask-permission-bridge] ERROR (deferring to normal flow): ${
        err instanceof Error ? (err.stack ?? err.message) : String(err)
      }\n`
    );
  });
}
